const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

/**
 * [PickPilot v10.5] FFmpeg 최종 가동 엔진
 * - Anti가 마운트한 /usr/bin/ffmpeg 경로를 직접 사용합니다.
 */
return (async () => {
  try {
    const item = $input.first().json;
    const dir = '/home/node/.n8n-files/pickpilot_data';

    // 1. 데이터 및 경로 추출
    const imageFiles = [item.img1, item.img2, item.img3];
    const rootFileName = item.root_fileName;
    const audioPath = path.join(dir, `${rootFileName}.mp3`);
    const outputPath = path.join(dir, `${rootFileName}_final.mp4`);

    // 2. 파일 물리적 존재 확인 (에러 방어)
    if (!fs.existsSync(audioPath)) {
      throw new Error(`[오디오 누락] 파일이 없습니다: ${audioPath}`);
    }
    imageFiles.forEach((f, idx) => {
      if (!f || !fs.existsSync(f)) {
        throw new Error(`[이미지 ${idx+1} 누락] 경로 확인 필요: ${f}`);
      }
    });

    // 3. FFmpeg 조립 명령 (15초 쇼츠 최적화: 4초/8초 오프셋 적용)
    // -y: 덮어쓰기 허용 / -shortest: 오디오 길이에 맞춤
    const command = `/usr/bin/ffmpeg -y \
    -loop 1 -t 5 -i "${imageFiles[0]}" \
    -loop 1 -t 5 -i "${imageFiles[1]}" \
    -loop 1 -t 5 -i "${imageFiles[2]}" \
    -i "${audioPath}" \
    -filter_complex "[0:v][1:v]xfade=transition=fade:duration=1:offset=4[v1]; [v1][2:v]xfade=transition=fade:duration=1:offset=8,format=yuv420p[v]" \
    -map "[v]" -map 3:a \
    -c:v libx264 -preset superfast -pix_fmt yuv420p -shortest "${outputPath}" 2>&1`;

    // 4. 조립 실행
    try {
      execSync(command);
    } catch (ffmpegErr) {
      throw new Error(`[FFmpeg 조립 실패] 로그: ${ffmpegErr.stdout?.toString()}`);
    }

    // 5. 결과 반환 (이후 노드에서 이 경로를 사용해 업로드합니다)
    return [{ 
      json: { 
        video_path: outputPath, 
        asin: item.asin, 
        root_fileName: rootFileName,
        status: "SUCCESS",
        message: "영상 조립 완료!" 
      } 
    }];
  } catch (e) {
    throw new Error(`[savevideo v10.5 Error] ${e.message}`);
  }
})();

/**
 * [PickPilot v9.0] Dual-Track Data Parser (YouTube + Medium)
 * CTO Fix: 핀터레스트 로직 완전 폐기, Medium 아티클 데이터 패키징, ShopMy Kiosk 강제
 */
try {
  const inputData = $input.first();
  if (!inputData) throw new Error("입력 데이터가 없습니다.");

  const geminiOutput = inputData.json;

  // 트래픽/할당량 초과 에러 방어
  if (geminiOutput.error) {
    const errMsg = geminiOutput.error.message || "";
    if (errMsg.includes("too many requests")) {
      throw new Error("⚠️ [트래픽 초과] 제미나이 API 대기열 초과. 잠시 후 재시도 필요.");
    }
    throw new Error(`Gemini API Error: ${errMsg}`);
  }

  // JSON 클렌징 및 파싱
  let content = geminiOutput.text || (geminiOutput.content?.parts?.[0]?.text) || "";
  let cleaned = content.replace(/```json/g, "").replace(/```/g, "").trim();
  let parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) parsed = parsed[0];

  // 절대 경로를 통한 시트 원본 데이터 참조
  const sheetData = $('Get row(s) in sheet').first().json;
  const asin = sheetData.asin || "UNKNOWN";
  const productTitle = sheetData.title || asin;
  const today = new Date().toISOString().split('T')[0].replace(/-/g, '');

  // 🔥 핵심: 모든 트래픽을 Kiosk로 집중시키는 ShopMy 하드코딩
  const shopMyLink = "https://shopmy.us/PickPilot"; 

  // 이미지 프롬프트 검증 (오직 영상용 3장만 처리)
  const imagePrompts = parsed.image_prompts || [];
  if (imagePrompts.length !== 3) {
    throw new Error(`이미지 프롬프트 개수 불일치. 현재: ${imagePrompts.length}장 (3장 필수)`);
  }

  // 이미지 생성 노드로 보낼 3개의 아이템(배열)으로 분할 리턴
  return imagePrompts.map((prompt, index) => {
    const rootName = `${today}_YT_${asin}`;
    return {
      json: {
        output_type: "VIDEO_SHORT", // 핀터레스트(PIN) 타입 원천 차단
        prompt: prompt.replace(/\[Product Title\]/gi, productTitle),
        index: index + 1,
        asin: asin,
        target_filename: `${rootName}_${(index + 1).toString().padStart(2, '0')}.png`,
        root_fileName: rootName,

        // 1. YouTube Shorts용 데이터 패키징
        shorts_script: parsed.shorts_script || "",

        // 2. Medium Blog용 데이터 패키징 (이후 미디엄 노드에서 이 데이터를 당겨 씁니다)
        medium_title: parsed.medium_article?.title || "",
        medium_body: parsed.medium_article?.body || "",
        medium_tags: parsed.medium_article?.tags || [],

        // 3. 통합 CTA 랜딩 주소
        shopmy_url: shopMyLink,

        // 데이터 추적용 원본 타이틀
        product_title: productTitle
      }
    };
  });

} catch (e) {
  throw new Error(`[CTO v9.0 Parser Fix] 파싱 실패: ${e.message}`);
}

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// [PickPilot v9.1] Stitch Engine - Path Fix & Lineage Protection
return (async () => {
  try {
    const items = $input.all();
    const returnItems = [];

    for (const item of items) {
      const json = item.json;
      const savedPath = json.saved_path;
      const templateType = json.template_type || 'None'; 

      // 파일 존재 여부 확인
      if (!savedPath || !fs.existsSync(savedPath)) {
        returnItems.push({ json: { ...json, stitch_status: "Skipped (No File)" } });
        continue;
      }

      // 1. 템플릿 파일 결정
      let templateFile = '';
      if (templateType === 'A') templateFile = 'VIDEO_A_hook_performance.png';
      else if (templateType === 'B') templateFile = 'PIN_B_buyers_guide_readnow.png';
      else if (templateType === 'C') templateFile = 'VIDEO_C_split_antidata.png';

      // [CTO FIX] 템플릿이 없는 경우: 선언되지 않은 outputPath 대신 원본 savedPath를 반환
      if (!templateFile) {
        returnItems.push({ 
          json: { 
            ...json, 
            saved_path: savedPath, // 원본 경로 유지
            stitch_status: "Success (No Template)",
            asin: json.asin, // 족보 유지
            target_filename: json.target_filename // 족보 유지
          } 
        });
        continue;
      }

      const templatePath = `/home/node/.n8n/assets/${templateFile}`;
      if (!fs.existsSync(templatePath)) {
         returnItems.push({ json: { ...json, saved_path: savedPath, stitch_status: `Error: Template ${templateFile} not found` } });
         continue;
      }

      // 2. FFmpeg 실행을 위한 경로 설정
      const dir = path.dirname(savedPath);
      const ext = path.extname(savedPath);
      const baseName = path.basename(savedPath, ext);
      const outputPath = path.join(dir, `${baseName}_stitched${ext}`);

      // [CTO FIX] Overlay 명령 실행
      const cmd = `ffmpeg -y -i "${savedPath}" -i "${templatePath}" -filter_complex "overlay=0:0" "${outputPath}"`;

      try {
        execSync(cmd);
        returnItems.push({ 
          json: { 
            ...json, 
            saved_path: outputPath, 
            original_path: savedPath, 
            stitch_status: "Success",
            asin: json.asin, // 족보 유지
            target_filename: json.target_filename // 족보 유지
          } 
        });
      } catch (e) {
        returnItems.push({ 
          json: { 
            ...json, 
            saved_path: savedPath, 
            stitch_status: `FFmpeg Error: ${e.message}`,
            asin: json.asin,
            target_filename: json.target_filename
          } 
        });
      }
    }
    return returnItems;
  } catch (e) {
    throw new Error(`[Stitch Engine v9.1 Error] ${e.message}`);
  }
})();

const fs = require('fs');
const path = require('path');

// [PickPilot v10.0] 다중 아이템 유실 방지 엔진 (3개 모두 보존)
const items = $input.all();
const metadataItems = $('Code in JavaScript1').all();
const results = [];

// 들어온 아이템 개수(3개)만큼 반복해서 모두 저장합니다.
for (let i = 0; i < items.length; i++) {
  try {
    const meta = metadataItems[i].json;
    const fileName = meta.target_filename;

    if (!fileName) throw new Error("target_filename을 찾을 수 없습니다.");

    const dirPath = '/home/node/.n8n-files/pickpilot_data'; 
    const filePath = path.join(dirPath, fileName);

    let binaryData;
    try {
      // i번째 아이템의 바이너리 데이터를 정확히 추출
      binaryData = await this.helpers.getBinaryDataBuffer(i, 'image');
    } catch (e) {
      binaryData = await this.helpers.getBinaryDataBuffer(i, 'data');
    }

    if (!binaryData) throw new Error("이미지 바이너리가 비어있습니다.");

    if (!fs.existsSync(dirPath)) fs.mkdirSync(dirPath, { recursive: true });
    fs.writeFileSync(filePath, binaryData);

    // 저장 성공한 데이터를 results 바구니에 차곡차곡 담습니다.
    results.push({ 
      json: { 
        ...meta, 
        saved_path: filePath, 
        status: "SUCCESS" 
      } 
    });
  } catch (error) {
    throw new Error(`[saveimage item ${i}] ${error.message}`);
  }
}

// 3개가 꽉 찬 바구니를 통째로 다음 노드로 넘깁니다!
  return results;

// [PickPilot v10.1] URL 생성기 - 로컬 경로 보존 엔진
const metadataItems = $('Code in JavaScript1').all();
const saveImageItems = $('saveimage').all(); // saveimage 노드의 데이터를 가져옵니다.

return $input.all().map((item, index) => {
  const gcsResponse = item.json;
  const metadata = metadataItems[index].json;
  const savedInfo = saveImageItems[index].json; // 저장된 로컬 경로 정보

  return {
    json: {
      ...gcsResponse,
      asin: metadata.asin,
      output_type: metadata.output_type,
      index: metadata.index,
      product_title: metadata.product_title,
      medium_title: metadata.medium_title,
      medium_body: metadata.medium_body,
      root_fileName: metadata.root_fileName,
      shopmy_url: metadata.shopmy_url,
      // ★핵심: Summarize 노드가 찾을 수 있도록 로컬 경로를 전달합니다.
      saved_path: savedInfo.saved_path, 
      public_url: `https://storage.googleapis.com/pickpilot-vault-01/${gcsResponse.name}`
    }
  };
});

/**
 * [PickPilot v10.8] 데이터 보정 키트 (Multi-Item Refinement)
 * Merge Multiplex 이후의 데이터를 정제하고 핀터레스트/영상 경로를 최종 확정합니다.
 */

const allItems = $input.all();
const results = [];

for (const item of allItems) {
    const json = item.json;
    const binary = item.binary || {};

    // 1. 필수 값 복구 (Merge 과정에서 누락될 수 있는 데이터)
    const outputType = json.output_type || "VIDEO_SHORT";
    const asin = json.asin || "UNKNOWN";

    // 2. 핀터레스트용 데이터는 별도 보정 없이 그대로 통과
    if (outputType === "PINTEREST_PIN") {
        results.push(item);
        continue;
    }

    // 3. 영상용 데이터는 영상 합성에 필요한 구조로 정규화
    results.push({
        json: {
            ...json,
            asin: asin,
            output_type: "VIDEO_SHORT",
            // 영상 인코딩 노드가 인식할 수 있는 파일명 구조 확정
            final_path: json.target_filename || `${asin}_video_frame.png`
        },
        binary: binary
    });
}

return results;

// [PickPilot v18.0] 로컬 경로 및 root_fileName 완벽 패키징
const input = $input.first().json; 

// 1. Summarize에서 합쳐진 로컬 경로(saved_path)와 웹 주소(public_url) 추출
const localImages = input.appended_saved_path || [];
const webImages = input.appended_public_url || [];

// 2. 이미지 개수 검증 (3장 필수)
if (localImages.length < 3) {
  throw new Error(`[공정 중단] 로컬 이미지가 ${localImages.length}장 뿐입니다. Summarize 노드에서 saved_path를 Append 했는지 확인하세요.`);
}

return {
  json: {
    asin: input.asin,
    root_fileName: input.root_fileName, // 오디오 매칭용 이름표
    product_title: input.product_title,
    medium_title: input.medium_title,
    medium_body: input.medium_body,
    // FFmpeg 합성을 위한 로컬 디스크 경로 강제 할당
    img1: localImages[0],
    img2: localImages[1],
    img3: localImages[2],
    // 블로그용 웹 주소 별도 보관
    web_img1: webImages[0],
    shopmy_url: input.shopmy_url || "https://shopmy.us/PickPilot"
  }
};

/**
 * [PickPilot v13.0] ASIN 기반 자동 다이렉트 링크 & 전환율 최적화 템플릿
 */
const input = $input.first().json;

const title = input.medium_title;
const body = input.medium_body;
const imageUrl = input.public_url; 
const asin = input.asin; // JSON에서 ASIN(상품 고유번호) 추출

// 🚨 핵심: ASIN을 이용해 아마존 다이렉트 주소를 코드가 알아서 생성합니다!
// (추후 공장장님의 아마존 어소시에이트 태그가 있다면 '?tag=내태그-20'을 뒤에 붙이면 됩니다)
const directProductUrl = `https://www.amazon.com/dp/${asin}`; 
const shopMyHubUrl = "https://shopmy.us/PickPilot";

// 글을 보기 좋게 문단(p태그)으로 쪼개고 여백 주기
const formattedBody = body.split('\n\n').map(paragraph => 
  `<p style="margin-bottom: 24px; color: #333; font-size: 16px;">${paragraph.replace(/\n/g, '<br>')}</p>`
).join('');

const htmlContent = `
<div style="max-width: 680px; margin: 0 auto; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; line-height: 1.8;">

  <figure style="margin: 0 0 30px 0; text-align: center;">
    <img src="${imageUrl}" alt="${title}" style="max-width: 100%; height: auto; border-radius: 12px; box-shadow: 0 4px 20px rgba(0,0,0,0.08);">
  </figure>

  <div style="background-color: #f8f9fa; border-left: 4px solid #cc0000; padding: 20px 25px; margin-bottom: 35px; border-radius: 0 8px 8px 0;">
    <h3 style="margin: 0 0 15px 0; font-size: 18px; color: #111;">💡 Why 3-Stars? (Crucial Flaw)</h3>
    <ul style="margin: 0; padding-left: 20px; color: #444; font-size: 15px;">
      <li style="margin-bottom: 8px;"><strong>Pros:</strong> Compact size with full-size suction power.</li>
      <li style="margin-bottom: 8px;"><strong>Cons:</strong> The hose connection detaches easily during use.</li>
      <li><strong>Takeaway:</strong> Consider the alternatives below if you need robust attachments.</li>
    </ul>
  </div>

  <div style="margin-bottom: 40px;">
    ${formattedBody}
  </div>

  <hr style="border: 0; border-top: 1px solid #eaeaea; margin: 40px 0;">

  <div style="display: flex; flex-direction: column; gap: 16px; margin-bottom: 20px;">

    <a href="${directProductUrl}" target="_blank"
       style="display: block; background-color: #0f172a; color: #ffffff; padding: 20px; text-decoration: none; border-radius: 12px; font-weight: 700; font-size: 18px; text-align: center; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);">
        Check Current Price on Amazon
    </a>

    <a href="${shopMyHubUrl}" target="_blank"
       style="display: block; background-color: #ffffff; color: #475569; padding: 18px; text-decoration: none; border-radius: 12px; font-weight: 600; font-size: 16px; text-align: center; border: 2px solid #e2e8f0; transition: all 0.2s;">
        View My 'Better Alternatives' List
    </a>

  </div>
</div>
`;

return {
  json: {
    title: title,
    content: htmlContent,
    contentFormat: "html",
    publishStatus: "draft" // 확인 후 Published로 변경 가능
  }
};
